def assemble_context(
    chunks: list[RetrievalChunk],
    graph_records: list[dict],
    max_tokens: int,
) -> str:
    """Cree una carga útil de contexto limitada con fragmentos y evidencia gráfica."""
    sections: list[str] = []
    for chunk in chunks:
        metadata = chunk.metadata
        sections.append(
            "\n".join(
                [
                    f"PATH: {metadata.get('path', 'unknown')}",
                    (
                        "LINES: "
                        f"{metadata.get('start_line', 0)}-"
                        f"{metadata.get('end_line', 0)}"
                    ),
                    f"SCORE: {chunk.score:.4f}",
                    chunk.text,
                ]
            )
        )

    if graph_records:
        sections.append("GRAPH_CONTEXT:")
        for record in graph_records[:50]:
            sections.append(str(record))

    context = SECTION_SEPARATOR.join(sections)
    max_chars = max(0, int(max_tokens) * 4)

def expand_with_graph(chunks: list[RetrievalChunk]) -> list[dict]:
    """Amplíe el contexto atravesando los vecinos del gráfico desde los símbolos recuperados."""
    symbol_ids = [item.id for item in chunks]
    if not symbol_ids:
        return []

    settings = get_settings()
    graph = GraphBuilder()
    try:
        return graph.expand_symbols(symbol_ids=symbol_ids, hops=settings.graph_hops)
    except Exception:
        return []
    finally:
        graph.close()

